// src/components/ProductForm.js

import React, { useState } from 'react';
import axios from 'axios';

const ProductForm = ({ refreshProducts }) => {
    const [product, setProduct] = useState({
        nome: '',
        descricao: '',
        codigo: '',
        categoria: '',
        preco: '',
        quantidade_minima: ''
    });

    // Função para atualizar o estado do produto
    const handleChange = (e) => {
        setProduct({ ...product, [e.target.name]: e.target.value });
    };

    // Função para enviar os dados do produto
    const handleSubmit = async (e) => {
        e.preventDefault();
    
        // Converte preco e quantidade_minima para números
        const productData = {
            ...product,
            preco: parseFloat(product.preco).toFixed(2), // Converte preco para um formato decimal com 2 casas
            quantidade_minima: parseInt(product.quantidade_minima), // Converte quantidade_minima para número
        };
    
        console.log("Dados do produto enviados:", productData); // Para depuração
    
        try {
            await axios.post('http://127.0.0.1:8000/api/produtos/', productData);
            refreshProducts(); // Atualiza a lista de produtos
            setProduct({
                nome: '',
                descricao: '',
                codigo: '',
                categoria: '',
                preco: '',
                quantidade_minima: ''
            });
        } catch (error) {
            console.error("Erro ao cadastrar produto:", error.response ? error.response.data : error.message);
            alert("Erro ao cadastrar produto: " + (error.response ? error.response.data : error.message));
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <input name="nome" placeholder="Nome" onChange={handleChange} required />
            <input name="descricao" placeholder="Descrição" onChange={handleChange} required />
            <input name="codigo" placeholder="Código" onChange={handleChange} required />
            <input name="categoria" placeholder="Categoria" onChange={handleChange} required />
            <input type="number" name="preco" placeholder="Preço" onChange={handleChange} required />
            <input type="number" name="quantidade_minima" placeholder="Quantidade Mínima" onChange={handleChange} required />
            <button type="submit">Adicionar Produto</button>
        </form>
    );
};

export default ProductForm;
